// Fetch and parse production order from Notion
const page = $input.first().json;
const props = page.properties || {};
return [{ json: {
  production_order_id: props['Order ID']?.rich_text?.[0]?.plain_text || `DOC-${Date.now()}`,
  client: props['Client']?.select?.name || 'Unknown',
  project_name: props['Project']?.title?.[0]?.plain_text || 'Documentary',
  topic: props['Topic']?.rich_text?.[0]?.plain_text || '',
  narrator_script: props['Script']?.rich_text?.[0]?.plain_text || '',
  research_urls: (props['Research URLs']?.rich_text?.[0]?.plain_text || '').split(',').map(u => u.trim()),
  shots: [],
  notion_page_id: page.id,
}}];

// Firecrawl MCP: Research topic — scrape URLs and ingest context
const order = $json;
return [{ json: { ...order, research_status: 'stub_complete', research_sources: order.research_urls.length }}];
// STUB: In production, calls Firecrawl MCP to scrape URLs, then ingests into Qdrant shot_library

// Claude: Generate narrator script + B-roll shot descriptions from research
const order = $json;
return [{ json: { ...order, script_generated: true, broll_descriptions: ['Environment establishing', 'Historical archive', 'Expert interview', 'Data visualization'] }}];
// STUB: Claude generates script from research + topic

// Multi-model B-roll generation
// Veo 3.1 for environments, Kling 3.0 for humans, Wan 2.6 for archival
const order = $json;
const shots = (order.broll_descriptions || []).map((desc, i) => ({
  shot_id: `DOC_SH${String(i+1).padStart(2,'0')}`,
  description: desc,
  model: desc.includes('archive') ? 'wan26_archival' : desc.includes('interview') ? 'kling_3.0' : 'veo_3.1',
  duration_seconds: desc.includes('interview') ? 8 : 5,
}));
return [{ json: { ...order, shots }}];

// RAG query for camera + lighting presets
const shot = $json;
return [{ json: { ...shot, camera_preset: 'documentary_handheld_35mm', lighting_preset: 'available_light_natural', assembled_prompt: `${shot.description}, documentary style, natural lighting, handheld camera, 35mm lens, Photo real, natural framing.` }}];

// Generation per model type
const shot = $json;
return [{ json: { ...shot, generation_status: 'stub', generation_cost: shot.duration_seconds * 0.15, output_path: `/tmp/cinema_studio/doc/${shot.shot_id}.mp4` }}];
// STUB: Routes to Veo/Kling/Wan based on shot.model

// Aggregate shots + Ken Burns on archive stills
const allShots = $input.all().map(i => i.json);
const totalCost = allShots.reduce((s, sh) => s + (sh.generation_cost || 0), 0);
return [{ json: { shots: allShots, total_generation_cost: totalCost, shot_count: allShots.length }}];

// ElevenLabs narrator voice
const order = $json;
return [{ json: { ...order, voiceover_path: '/tmp/cinema_studio/doc/narrator.mp3', voiceover_cost: 0.05 }}];
// STUB: ElevenLabs narration with documentary voice

// Remotion composition using Generic template (documentary config)
// Ken Burns on stills, lower thirds with expert names, chapter markers
const order = $json;
return [{ json: { ...order, remotion_template: 'Generic', remotion_command: `npx remotion render src/index.ts Generic --props=doc_props.json --output /tmp/cinema_studio/doc/composite.mp4` }}];

// FFmpeg: documentary color grade + audio normalization
const order = $json;
return [{ json: { ...order, grade_command: `python tools/color_grade.py composite.mp4 --chain "neutral_normalize,fuji_eterna_250d" --grain 0.10 --output graded.mp4`, audio_normalization: '-16 LUFS' }}];

// YouTube chapter generation from script
const order = $json;
return [{ json: { ...order, youtube_chapters: '0:00 Introduction
0:30 Background
1:15 Analysis
2:00 Conclusion', platform_encodes: [{platform: 'youtube', aspect: '16:9'}] }}];

// Cost reconciliation + Notion update
const order = $json;
const total = (order.total_generation_cost || 0) + (order.voiceover_cost || 0);
return [{ json: { production_order_id: order.production_order_id, total_cost: total, status: 'QC Review' }}];
